// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		count = 4 // default to 4 pings if invalid count
	}

	// Execute ping command with -c flag for count (Unix/Linux/Mac)
	// For Windows, use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Try Windows format if Unix fails
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		output, err = cmd.CombinedOutput()
		if err != nil {
			return 0, fmt.Errorf("failed to ping host %s: %w", host, err)
		}
	}

	outputStr := string(output)

	// Try to extract average latency from different ping output formats

