			}
		case c == ':':
			// colon only allowed for IPv6 addresses
		default:
			return false
		}
	}

	// Additional check: no consecutive dots
	if strings.Contains(host, "..") {
		return false
	}

	// Host should not start or end with dot or hyphen
	first := host[0]
	last := host[len(host)-1]
	if first == '.' || first == '-' || last == '.' || last == '-' {
		return false
	}

	return true
}

