	}

	// Execute ping command with -c flag for count (Unix-like systems)
	// For Windows, use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)

	// Try to find average latency from output
	// Common patterns:
	// Linux/macOS: "rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms"
	// Or: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/3.456 ms"

	// Pattern for rtt/round-trip line with avg value
	rttPattern := regexp.MustCompile(`(?:rtt|round-trip)[^=]+=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := rttPattern.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Alternative pattern for some systems that show "time=Xms" per line
	// Calculate average manually
	timePattern := regexp.MustCompile(`time[=<]([\d.]+)\s*ms`)
	times := timePattern.FindAllStringSubmatch(outputStr, -1)

	if len(times) > 0 {
		var total float64
		for _, t := range times {
			if len(t) >= 2 {
				val, err := strconv.ParseFloat(t[1], 64)
				if err == nil {
					total += val
				}
			}
		}
		if len(times) > 0 {
			return total / float64(len(times)), nil
		}
	}

	// Try Windows format: "Average = Xms" or "Minimum = Xms, Maximum = Yms, Average = Zms"
	winAvgPattern := regexp.MustCompile(`Average\s*[=:]\s*(\d+)ms?`)
	winMatches := winAvgPattern.FindStringSubmatch(outputStr)
	if len(winMatches) >= 2 {
		avg, err := strconv.ParseFloat(winMatches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not parse ping output: %s", strings.TrimSpace(outputStr))
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
