package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute ping command with -c flag for count (Linux/macOS)
	// For Windows compatibility, we would need different flags
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Try to find average time from ping output
	// Common formats:
	// Linux: rtt min/avg/max/mdev = 0.042/0.045/0.048/0.002 ms
	// macOS: round-trip min/avg/max/stddev = 0.042/0.045/0.048/0.002 ms

	// Pattern to match average time in ping output
	patterns := []string{
		`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`,           // Linux
		`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`, // macOS
		`Average = (\d+)ms`, // Windows (basic pattern)
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) >= 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %v", err)
			}
			return avg, nil
		}
	}

	// Fallback: try to extract individual ping times and calculate average
	timePattern := `time=([\d.]+) ms`
	re := regexp.MustCompile(timePattern)
	matches := re.FindAllStringSubmatch(outputStr, -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse ping output: %s", outputStr)
	}

	var total float64
	for _, match := range matches {
		if len(match) >= 2 {
			t, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += t
		}
	}

	if len(matches) == 0 {
		return 0, fmt.Errorf("no valid ping times found in output")
	}

	return total / float64(len(matches)), nil
}

func main() {
	// Example usage
	host := "127.0.0.1"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

