package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with -c flag for count (Unix/Linux/macOS)
	// Note: On Windows, the flag would be -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Try to find average latency from different ping output formats
	// Common formats include:
	// - "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.012 ms"
	// - "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"

	// Pattern to match rtt/round-trip statistics line
	rttPattern := regexp.MustCompile(`(?:round-trip|rtt)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := rttPattern.FindStringSubmatch(outputStr)

	if len(matches) >= 2 {
		avgLatency, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avgLatency, nil
	}

	// Fallback: try to extract individual ping times and calculate average
	timePattern := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	times := timePattern.FindAllStringSubmatch(outputStr, -1)

	if len(times) == 0 {
		return 0, fmt.Errorf("could not find latency data in ping output: %s", outputStr)
	}

	var total float64
	for _, t := range times {
		if len(t) >= 2 {
			val, err := strconv.ParseFloat(t[1], 64)
			if err != nil {
				continue
			}
			total += val
		}
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	return total / float64(len(times)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

