package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with -c flag for count (Unix/Linux/macOS)
	// Note: On Windows, use "-n" instead of "-c"
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Try to find average latency from different ping output formats

	// Linux/macOS format: "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"
	rttRegex := regexp.MustCompile(`rtt[^=]+=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := rttRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Alternative format for some systems: "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.012 ms"
	roundTripRegex := regexp.MustCompile(`round-trip[^=]+=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches = roundTripRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Windows format: "Average = 0ms" or "Average = 0.0ms"
	winAvgRegex := regexp.MustCompile(`[Aa]verage\s*=\s*([\d.]+)\s*ms?`)
	matches = winAvgRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// If no average found, try to calculate from individual times
	// Look for "time=0.123 ms" patterns
	timeRegex := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	allTimes := timeRegex.FindAllStringSubmatch(outputStr, -1)

	var total float64
	validCount := 0
	for _, match := range allTimes {
		if len(match) > 1 {
			t, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				total += t
				validCount++
			}
		}
	}

	if validCount > 0 {
		return total / float64(validCount), nil
	}

	return 0, fmt.Errorf("could not parse ping output to determine average latency")
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", latency)
}

