package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute ping command with -c flag for count (Unix/Linux/macOS)
	// For Windows, you would use "-n" instead of "-c"
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Try to find average time in the output
	// Common patterns:
	// Linux: "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"
	// macOS: "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.012 ms"

	// Pattern for Linux format
	linuxPattern := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := linuxPattern.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	// Pattern for macOS format
	macPattern := regexp.MustCompile(`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches = macPattern.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	// Fallback: try to extract individual ping times and calculate average
	// Pattern like "time=0.123 ms" or "time=0.456ms"
	timePattern := regexp.MustCompile(`time[=<>]([\d.]+)\s*ms`)
	timeMatches := timePattern.FindAllStringSubmatch(outputStr, -1)

	if len(timeMatches) == 0 {
		return 0, fmt.Errorf("could not parse ping output: no latency data found")
	}

	var total float64
	for _, match := range timeMatches {
		if len(match) >= 2 {
			t, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += t
		}
	}

	if len(timeMatches) == 0 {
		return 0, fmt.Errorf("could not parse any valid latency values")
	}

	average := total / float64(len(timeMatches))
	return average, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

