import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		count = 4 // default to 4 pings if invalid count
	}

	// Execute ping command with -c flag for count (Unix/Linux/Mac)
	// For Windows, use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)

	// Try to find average latency from different ping output formats

	// Linux/Mac format: "rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms"
	rttRegex := regexp.MustCompile(`rtt [^=]+=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
	matches := rttRegex.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Alternative format for some systems: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/3.456 ms"
	rttAltRegex := regexp.MustCompile(`round-trip [^=]+=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
	matches = rttAltRegex.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Windows format: look for "Average = Xms" or similar
	winAvgRegex := regexp.MustCompile(`[Aa]verage\s*[=:]\s*(\d+(?:\.\d+)?)\s*ms?`)
	matches = winAvgRegex.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// If no average found, try to calculate from individual ping times
	timeRegex := regexp.MustCompile(`time[=:](\d+(?:\.\d+)?)\s*ms`)
	allTimes := timeRegex.FindAllStringSubmatch(outputStr, -1)

	if len(allTimes) > 0 {
		var total float64
		for _, match := range allTimes {
			if len(match) >= 2 {
				t, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					total += t
				}
			}
		}
		if len(allTimes) > 0 {
			return total / float64(len(allTimes)), nil
		}
	}

	return 0, fmt.Errorf("could not parse ping output: %s", outputStr)
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

