package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		count = 4 // default to 4 pings if invalid count
	}

	// Execute ping command with -c flag for count (Unix/Linux/Mac)
	// For Windows, use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)

	// Try to find average latency from different ping output formats

	// Linux/Unix format: "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"
	rttRegex := regexp.MustCompile(`rtt[^=]+=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
	matches := rttRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Alternative format: "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.012 ms"
	roundTripRegex := regexp.MustCompile(`round-trip[^=]+=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+\s*ms`)
	matches = roundTripRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// macOS format: "avg = 0.456 ms"
	avgRegex := regexp.MustCompile(`avg\s*=\s*([\d\.]+)\s*ms`)
	matches = avgRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Try to calculate average from individual ping times
	// Look for time=XX.X ms patterns
	timeRegex := regexp.MustCompile(`time=([\d\.]+)\s*ms`)
	timeMatches := timeRegex.FindAllStringSubmatch(outputStr, -1)

	var total float64
	var validCount int
	for _, match := range timeMatches {
		if len(match) > 1 {
			t, err := strconv.ParseFloat(match[1], 64)
			if err == nil {
				total += t
				validCount++
			}
		}
	}

	if validCount > 0 {
		return total / float64(validCount), nil
	}

	return 0, fmt.Errorf("could not parse ping output: %s", outputStr)
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

