// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with -c flag for count (Unix/Linux/macOS)
	// Note: On Windows, this would use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Try to extract average time from different ping output formats
	// Common format: "avg = X.Y" or "avg/X.Y/" or "average = X.Y"

	// Pattern 1: Linux format "min/avg/max/mdev = X/Y/Z/W ms"
	linuxPattern := regexp.MustCompile(`min/avg/max[^=]*=\s*[\d\.]+/([\d\.]+)/`)
	matches := linuxPattern.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Pattern 2: macOS/BSD format "round-trip min/avg/max/stddev = X/Y/Z/W ms"
	macosPattern := regexp.MustCompile(`round-trip\s+min/avg/max[^=]*=\s*[\d\.]+/([\d\.]+)/`)
	matches = macosPattern.FindStringSubmatch(outputStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Pattern 3: Generic "average = X.Y" or "avg = X.Y"
	genericPattern := regexp.MustCompile(`(?:average|avg)[^=]*=\s*([\d\.]+)`)
	matches = genericPattern.FindStringSubmatch(strings.ToLower(outputStr))
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Pattern 4: Look for "time=X.Y ms" in individual ping lines and calculate average
	timePattern := regexp.MustCompile(`time=([\d\.]+)\s*ms`)
	allMatches := timePattern.FindAllStringSubmatch(outputStr, -1)
	if len(allMatches) > 0 {
