// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute ping command with -c flag for count (Unix-like systems)
	// For Windows, this would need adjustment to use -n instead
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse the output to find average latency
	// Look for patterns like "avg = 23.456" or "average = 23.456"
	outputStr := string(output)

	// Try multiple regex patterns to match different ping output formats
	patterns := []string{
		`avg[\/=]\s*(\d+\.?\d*)`,           // avg = 23.456 or avg/23.456
		`average[\/=]?\s*(\d+\.?\d*)`,       // average = 23.456 or average/23.456
		`round-trip.*=\s*[\d.]+\/(\d+\.?\d+)`, // round-trip min/avg/max = 0.123/23.456/45.678
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) > 1 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				return avg, nil
			}
		}
	}

	// If no average found, try to calculate from individual times
	timePattern := `time=(\d+\.?\d*)\s*ms`
	re := regexp.MustCompile(timePattern)
	matches := re.FindAllStringSubmatch(outputStr, -1)

	if len(matches) >= count {
		var total float64
		validCount := 0
		for _, match := range matches {
			if len(match) > 1 {
				t, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					total += t
					validCount++
				}
			}
		}
		if validCount > 0 {
			return total / float64(validCount), nil
		}
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

