package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute ping command with -c flag for count (Unix-like systems)
	// For Windows, this would need adjustment to use -n instead
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Try to find average time from different ping output formats
	// Common format: "avg/stddev = 23.456/1.234 ms" or "Average = 23ms" or "time=23.4 ms"

	// Try Unix-style avg/stddev format first
	avgRegex := regexp.MustCompile(`avg(?:/stddev)?\s*[=\/]\s*(\d+\.?\d*)`)
	matches := avgRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Try to find average from "Average" line (Windows style)
	averageRegex := regexp.MustCompile(`[Aa]verage\s*[=:]?\s*(\d+\.?\d*)`)
	matches = averageRegex.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Fallback: calculate average from individual time values
	timeRegex := regexp.MustCompile(`time[=:](\d+\.?\d*)\s*ms`)
	times := timeRegex.FindAllStringSubmatch(outputStr, -1)
	if len(times) == 0 {
		return 0, fmt.Errorf("could not parse ping output: no time values found")
	}

	var total float64
	for _, t := range times {
		val, err := strconv.ParseFloat(t[1], 64)
		if err != nil {
			continue
		}
		total += val
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("could not parse any valid time values")
	}

	return total / float64(len(times)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.3f ms\n", host, count, avgLatency)
}

