package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns
// the average latency in milliseconds. It uses the os/exec package to execute
// the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		count = 4 // default to 4 pings if invalid count
	}

	// Execute ping command with -c flag for count (Unix/Linux/Mac)
	// For Windows, use -n instead of -c
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)

	// Try to find average time from different ping output formats
	// Common formats:
	// Linux: "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.012 ms"
	// macOS: "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.012 ms"

	// Pattern for rtt/round-trip line with average
	rttPattern := regexp.MustCompile(`(?:rtt|round-trip)[^=]+=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := rttPattern.FindStringSubmatch(outputStr)

	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Alternative: try to parse individual ping times and calculate average
	// Pattern for "time=0.123 ms" or "time=1.23 ms"
	timePattern := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	timeMatches := timePattern.FindAllStringSubmatch(outputStr, -1)

	if len(timeMatches) > 0 {
		var total float64
		for _, match := range timeMatches {
			if len(match) >= 2 {
				t, err := strconv.ParseFloat(match[1], 64)
				if err == nil {
					total += t
				}
			}
		}
		if len(timeMatches) > 0 {
			return total / float64(len(timeMatches)), nil
		}
	}

	return 0, fmt.Errorf("could not parse ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avgLatency)
}

